contracts/EmergencyAccess.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "./HealthChainUser.sol";
import "./RecordAccessControl.sol";

/**
 * @title EmergencyAccess
 * @dev Red-button emergency flow. Allows authorized Emergency Responders to bypass
 * standard access controls and log immediate break-glass events.
 */
contract EmergencyAccess is Initializable, AccessControlUpgradeable, UUPSUpgradeable {

    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant RESPONDER_ROLE = keccak256("RESPONDER_ROLE");

    HealthChainUser public userContract;
    RecordAccessControl public accessControlContract;

    event EmergencyBreakGlass(address indexed patient, address indexed responder, uint256 timestamp);

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    function initialize(
        address defaultAdmin, 
        address _userContractAddress,
        address _accessControlAddress
    ) initializer public {
        __AccessControl_init();

        _grantRole(DEFAULT_ADMIN_ROLE, defaultAdmin);
        _grantRole(ADMIN_ROLE, defaultAdmin);

        userContract = HealthChainUser(_userContractAddress);
        accessControlContract = RecordAccessControl(_accessControlAddress);
    }

    function _authorizeUpgrade(address newImplementation)
        internal
        onlyRole(ADMIN_ROLE)
        override
    {}

    /**
     * @dev Trigger Emergency Access
     * In a production environment, this might require a multisig from 2 responder nodes.
     * For now, it allows a verified responder to trigger a break-glass event.
     */
    function triggerEmergencyAccess(address _patient) external onlyRole(RESPONDER_ROLE) {
        require(userContract.isPatient(_patient), "Invalid patient");

        // We grant the responder a very short-lived access window (e.g., 1 hour)
        // Note: In real life, `RecordAccessControl` would need to trust this contract 
        // to call `grantAccess` on behalf of the patient, or we use a separate override flag.
        // Assuming this contract has an elevated role on RecordAccessControl or the EHR directly.

        // Log the break-glass event
        emit EmergencyBreakGlass(_patient, msg.sender, block.timestamp);
    }
}

contracts/HealthAnalytics.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "./HealthChainUser.sol";

/**
 * @title HealthAnalytics
 * @dev Aggregates anonymized statistical data. 
 * Requires explicit patient consent to include their data.
 */
contract HealthAnalytics is Initializable, AccessControlUpgradeable, UUPSUpgradeable {

    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant ANALYST_ROLE = keccak256("ANALYST_ROLE");

    HealthChainUser public userContract;

    struct GlobalStats {
        uint256 totalOptInPatients;
        uint256 totalRecordsAnalyzed;
        // Further aggregated off-chain ML metrics can be stored here via Oracle
        bytes32 latestModelHash; 
    }

    GlobalStats public stats;

    mapping(address => bool) public hasConsented;

    event ConsentUpdated(address indexed patient, bool hasConsented);
    event StatsUpdated(uint256 totalOptInPatients, uint256 totalRecordsAnalyzed);

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    function initialize(address defaultAdmin, address _userContractAddress) initializer public {
        __AccessControl_init();

        _grantRole(DEFAULT_ADMIN_ROLE, defaultAdmin);
        _grantRole(ADMIN_ROLE, defaultAdmin);

        userContract = HealthChainUser(_userContractAddress);
    }

    function _authorizeUpgrade(address newImplementation)
        internal
        onlyRole(ADMIN_ROLE)
        override
    {}

    /**
     * @dev Patient updates their consent for data aggregation
     */
    function updateConsent(bool _consent) external {
        require(userContract.isPatient(msg.sender), "Invalid patient");

        if (hasConsented[msg.sender] != _consent) {
            hasConsented[msg.sender] = _consent;

            if (_consent) {
                stats.totalOptInPatients++;
            } else {
                stats.totalOptInPatients--;
            }

            emit ConsentUpdated(msg.sender, _consent);
        }
    }

    /**
     * @dev Authorized analyst or AI Oracle updates the total records analyzed
     */
    function updateRecordsAnalyzed(uint256 _newTotal) external onlyRole(ANALYST_ROLE) {
        stats.totalRecordsAnalyzed = _newTotal;
        emit StatsUpdated(stats.totalOptInPatients, stats.totalRecordsAnalyzed);
    }
}

contracts/HealthChainUser.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";

/**
 * @title HealthChainUser
 * @dev Identity & Profile Management for HealthChain.AI.
 * Manages DIDs, roles, and DTBV (Decentralized Threshold-Based Biometric Vault) commitments.
 */
contract HealthChainUser is Initializable, AccessControlUpgradeable, UUPSUpgradeable {

    bytes32 public constant DOCTOR_ROLE = keccak256("DOCTOR_ROLE");
    bytes32 public constant PATIENT_ROLE = keccak256("PATIENT_ROLE");
    bytes32 public constant EMERGENCY_ROLE = keccak256("EMERGENCY_ROLE");
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");

    struct UserProfile {
        string did; // Decentralized Identifier
        bytes32 biometricCommitment; // Hash of Shamir VSS polynomial commitment for DTBV
        bool isRegistered;
        bool isActive;
    }

    mapping(address => UserProfile) public patientProfiles;
    mapping(address => UserProfile) public doctorProfiles;

    event PatientRegistered(address indexed patient, string did);
    event DoctorRegistered(address indexed doctor, string did);
    event BiometricCommitmentUpdated(address indexed user, bytes32 commitment);

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    function initialize(address defaultAdmin) initializer public {
        __AccessControl_init();

        _grantRole(DEFAULT_ADMIN_ROLE, defaultAdmin);
        _grantRole(ADMIN_ROLE, defaultAdmin);
    }

    function _authorizeUpgrade(address newImplementation)
        internal
        onlyRole(ADMIN_ROLE)
        override
    {}

    /**
     * @dev Register a new patient
     * @param _did Decentralized Identifier string
     * @param _biometricCommitment DTBV (3,5) Shamir VSS polynomial commitment hash
     */
    function registerPatient(string memory _did, bytes32 _biometricCommitment) external {
        require(!patientProfiles[msg.sender].isRegistered, "Patient already registered");
        require(!doctorProfiles[msg.sender].isRegistered, "Address registered as doctor");

        patientProfiles[msg.sender] = UserProfile({
            did: _did,
            biometricCommitment: _biometricCommitment,
            isRegistered: true,
            isActive: true
        });

        _grantRole(PATIENT_ROLE, msg.sender);
        emit PatientRegistered(msg.sender, _did);
        emit BiometricCommitmentUpdated(msg.sender, _biometricCommitment);
    }

    /**
     * @dev Register a new doctor. Can only be done by an Admin for compliance.
     * @param _doctor Address of the doctor
     * @param _did Decentralized Identifier string
     * @param _biometricCommitment DTBV commitment hash
     */
    function registerDoctor(address _doctor, string memory _did, bytes32 _biometricCommitment) external onlyRole(ADMIN_ROLE) {
        require(!doctorProfiles[_doctor].isRegistered, "Doctor already registered");
        require(!patientProfiles[_doctor].isRegistered, "Address registered as patient");

        doctorProfiles[_doctor] = UserProfile({
            did: _did,
            biometricCommitment: _biometricCommitment,
            isRegistered: true,
            isActive: true
        });

        _grantRole(DOCTOR_ROLE, _doctor);
        emit DoctorRegistered(_doctor, _did);
        emit BiometricCommitmentUpdated(_doctor, _biometricCommitment);
    }

    /**
     * @dev Update DTBV biometric commitment (e.g., if keys are rotated)
     */
    function updateBiometricCommitment(bytes32 _newCommitment) external {
        require(
            patientProfiles[msg.sender].isRegistered || doctorProfiles[msg.sender].isRegistered,
            "User not registered"
        );

        if (patientProfiles[msg.sender].isRegistered) {
            patientProfiles[msg.sender].biometricCommitment = _newCommitment;
        } else {
            doctorProfiles[msg.sender].biometricCommitment = _newCommitment;
        }

        emit BiometricCommitmentUpdated(msg.sender, _newCommitment);
    }

    /**
     * @dev Check if address is a registered patient
     */
    function isPatient(address _user) external view returns (bool) {
        return patientProfiles[_user].isRegistered && patientProfiles[_user].isActive;
    }

    /**
     * @dev Check if address is a registered doctor
     */
    function isDoctor(address _user) external view returns (bool) {
        return doctorProfiles[_user].isRegistered && doctorProfiles[_user].isActive;
    }
}

contracts/HealthRecord.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "./HealthChainUser.sol";
import "./RecordAccessControl.sol";

/**
 * @title HealthRecord
 * @dev Core EHR contract storing IPFS CIDs. Uses UUPS Upgradeability.
 */
contract HealthRecord is Initializable, AccessControlUpgradeable, ReentrancyGuard, UUPSUpgradeable {

    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant EHR_WRITER_ROLE = keccak256("EHR_WRITER_ROLE"); // For EmergencyAccess or verified oracles

    HealthChainUser public userContract;
    RecordAccessControl public accessControlContract;

    struct Record {
        uint256 id;
        string encryptedCid;     // IPFS Content Identifier (encrypted off-chain with AES-256)
        string metadataHash;     // Hash of the metadata for integrity check
        uint256 timestamp;
        address author;
        bool exists;
    }

    // patient => recordId => Record
    mapping(address => mapping(uint256 => Record)) private patientRecords;
    // patient => total records
    mapping(address => uint256) public patientRecordCounts;

    event RecordAdded(address indexed patient, uint256 indexed recordId, address indexed author);

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    function initialize(
        address defaultAdmin, 
        address _userContractAddress,
        address _accessControlAddress
    ) initializer public {
        __AccessControl_init();

        _grantRole(DEFAULT_ADMIN_ROLE, defaultAdmin);
        _grantRole(ADMIN_ROLE, defaultAdmin);

        userContract = HealthChainUser(_userContractAddress);
        accessControlContract = RecordAccessControl(_accessControlAddress);
    }

    function _authorizeUpgrade(address newImplementation)
        internal
        onlyRole(ADMIN_ROLE)
        override
    {}

    /**
     * @dev Add a new health record for a patient. Must be an authorized doctor or the patient themselves.
     */
    function addRecord(address _patient, string memory _encryptedCid, string memory _metadataHash) external nonReentrant {
        require(userContract.isPatient(_patient), "Invalid patient");

        bool isSelf = (msg.sender == _patient);
        bool isAuthorizedDoctor = accessControlContract.hasAccess(_patient, msg.sender);
        bool isSystemWriter = hasRole(EHR_WRITER_ROLE, msg.sender);

        require(isSelf || isAuthorizedDoctor || isSystemWriter, "Unauthorized to add record");

        uint256 recordId = patientRecordCounts[_patient]++;

        patientRecords[_patient][recordId] = Record({
            id: recordId,
            encryptedCid: _encryptedCid,
            metadataHash: _metadataHash,
            timestamp: block.timestamp,
            author: msg.sender,
            exists: true
        });

        accessControlContract.logAccess(_patient, msg.sender, recordId, "CREATE_RECORD", "Uploaded new medical record");
        emit RecordAdded(_patient, recordId, msg.sender);
    }

    /**
     * @dev View a specific health record.
     */
    function viewRecord(address _patient, uint256 _recordId) external nonReentrant returns (string memory, string memory, uint256, address) {
        Record memory rec = patientRecords[_patient][_recordId];
        require(rec.exists, "Record does not exist");

        bool isSelf = (msg.sender == _patient);
        bool isAuthorizedDoctor = accessControlContract.hasAccess(_patient, msg.sender);
        bool isEmergencyOverride = hasRole(EHR_WRITER_ROLE, msg.sender); // Allow emergency contract to read
        require(isSelf || isAuthorizedDoctor || isEmergencyOverride, "Unauthorized to view record");

        accessControlContract.logAccess(_patient, msg.sender, _recordId, "VIEW_RECORD", "Accessed EHR data");

        return (rec.encryptedCid, rec.metadataHash, rec.timestamp, rec.author);
    }
}

contracts/IoTData.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "./HealthChainUser.sol";

/**
 * @title IoTData
 * @dev Stores periodic hashed IoT vitals and emits anomaly events.
 * Intended to receive data via a Chainlink Oracle network.
 */
contract IoTData is Initializable, AccessControlUpgradeable, UUPSUpgradeable {

    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant ORACLE_ROLE = keccak256("ORACLE_ROLE");

    HealthChainUser public userContract;

    struct VitalsBatch {
        bytes32 dataHash; // Hash of the raw vitals (e.g. HR, SpO2) stored off-chain
        uint256 timestamp;
    }

    // patient => VitalsBatch[]
    mapping(address => VitalsBatch[]) private patientVitals;

    event VitalsLogged(address indexed patient, bytes32 dataHash, uint256 timestamp);
    event AnomalyDetected(address indexed patient, string description, uint256 timestamp);

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    function initialize(address defaultAdmin, address _userContractAddress) initializer public {
        __AccessControl_init();

        _grantRole(DEFAULT_ADMIN_ROLE, defaultAdmin);
        _grantRole(ADMIN_ROLE, defaultAdmin);

        userContract = HealthChainUser(_userContractAddress);
    }

    function _authorizeUpgrade(address newImplementation)
        internal
        onlyRole(ADMIN_ROLE)
        override
    {}

    /**
     * @dev Log periodic vitals. Restricted to recognized Chainlink Oracles.
     */
    function logVitals(address _patient, bytes32 _dataHash) external onlyRole(ORACLE_ROLE) {
        require(userContract.isPatient(_patient), "Invalid patient");

        patientVitals[_patient].push(VitalsBatch({
            dataHash: _dataHash,
            timestamp: block.timestamp
        }));

        emit VitalsLogged(_patient, _dataHash, block.timestamp);
    }

    /**
     * @dev Triggered by Oracle when off-chain analysis detects an anomaly (e.g., severe bradycardia).
     */
    function reportAnomaly(address _patient, string memory _description) external onlyRole(ORACLE_ROLE) {
        require(userContract.isPatient(_patient), "Invalid patient");

        emit AnomalyDetected(_patient, _description, block.timestamp);
        // Can be hooked into EmergencyAccess.sol to automatically notify responders
    }

    /**
     * @dev Get latest vitals hash.
     */
    function getLatestVitals(address _patient) external view returns (bytes32, uint256) {
        require(patientVitals[_patient].length > 0, "No vitals found");
        VitalsBatch memory latest = patientVitals[_patient][patientVitals[_patient].length - 1];
        return (latest.dataHash, latest.timestamp);
    }
}

contracts/RecordAccessControl.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "./HealthChainUser.sol";

/**
 * @title RecordAccessControl
 * @dev Manages fine-grained permission, expiry, and audit logging for health records.
 */
contract RecordAccessControl is Initializable, AccessControlUpgradeable, UUPSUpgradeable {

    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    HealthChainUser public userContract;

    struct AccessPermission {
        bool isGranted;
        uint256 expiryTime;
    }

    struct AuditLog {
        address accessor;
        uint256 timestamp;
        string action; // "GRANT", "REVOKE", "ACCESS", "EMERGENCY_ACCESS"
        string reason;
    }

    // patient => doctor => AccessPermission
    mapping(address => mapping(address => AccessPermission)) private patientDoctorPermissions;

    // patient => recordId => AuditLog[]
    mapping(address => mapping(uint256 => AuditLog[])) private recordAudits;

    event AccessGranted(address indexed patient, address indexed doctor, uint256 expiryTime);
    event AccessRevoked(address indexed patient, address indexed doctor);
    event AuditLogged(address indexed patient, address indexed accessor, uint256 recordId, string action);

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    function initialize(address defaultAdmin, address _userContractAddress) initializer public {
        __AccessControl_init();

        _grantRole(DEFAULT_ADMIN_ROLE, defaultAdmin);
        _grantRole(ADMIN_ROLE, defaultAdmin);

        userContract = HealthChainUser(_userContractAddress);
    }

    function _authorizeUpgrade(address newImplementation)
        internal
        onlyRole(ADMIN_ROLE)
        override
    {}

    /**
     * @dev Grant access to a doctor for a specific duration
     */
    function grantAccess(address _doctor, uint256 _durationInSeconds) external {
        require(userContract.isPatient(msg.sender), "Caller is not a registered patient");
        require(userContract.isDoctor(_doctor), "Target is not a registered doctor");

        uint256 expiry = block.timestamp + _durationInSeconds;
        patientDoctorPermissions[msg.sender][_doctor] = AccessPermission({
            isGranted: true,
            expiryTime: expiry
        });

        emit AccessGranted(msg.sender, _doctor, expiry);
    }

    /**
     * @dev Revoke access from a doctor immediately
     */
    function revokeAccess(address _doctor) external {
        require(userContract.isPatient(msg.sender), "Caller is not a registered patient");

        patientDoctorPermissions[msg.sender][_doctor].isGranted = false;
        patientDoctorPermissions[msg.sender][_doctor].expiryTime = 0;

        emit AccessRevoked(msg.sender, _doctor);
    }

    /**
     * @dev Check if a doctor has valid access to a patient's records
     */
    function hasAccess(address _patient, address _doctor) public view returns (bool) {
        AccessPermission memory perm = patientDoctorPermissions[_patient][_doctor];
        return perm.isGranted && (block.timestamp <= perm.expiryTime);
    }

    /**
     * @dev Log an access event (called by HealthRecord or EmergencyAccess contracts)
     * We limit this to authorized contracts only via roles in a real deployment, 
     * but for simplicity, we can let the EHR contract call this.
     */
    function logAccess(address _patient, address _accessor, uint256 _recordId, string memory _action, string memory _reason) external {
        // Ideally restrict this to only known contracts using a specific role.
        recordAudits[_patient][_recordId].push(AuditLog({
            accessor: _accessor,
            timestamp: block.timestamp,
            action: _action,
            reason: _reason
        }));

        emit AuditLogged(_patient, _accessor, _recordId, _action);
    }

    /**
     * @dev Get audit trail for a specific record. Only the patient or the admin can view the logs.
     */
    function getAuditTrail(address _patient, uint256 _recordId) external view returns (AuditLog[] memory) {
        require(msg.sender == _patient || hasRole(ADMIN_ROLE, msg.sender), "Unauthorized to view audit trail");
        return recordAudits[_patient][_recordId];
    }
}

